import _ from 'lodash';
import moment from 'moment';
import { ZodError } from 'zod';

import AppConstants from '@/constants/app.constants';
import { SupportedLanguage, SupportedUnit } from '@/constants/app.constants';
import { Ball } from '@/models/ball';
import { BallPosition } from '@/models/ball-position';
import { Resource } from '@/models/resource';
import { MandatoryOrHavingError } from '@/models/types';
import { ApiClient } from '@/services/clients/web-api-client';
import { ServiceError } from '@/services/errors/service-error';
import {
  AnalyzeType,
  analyzeTypeValuesMap,
  ResourceDateFilterType,
  ResourcesApiInterface,
  ResourceSortType,
} from '@/services/interfaces/resources-api.interface';
import { LocalStorageService } from '@/services/local-storage/local-storage.service';
import { UIUtil } from '@/utils/ui.util';
import { videoAnalyzeDtoValidator } from '@/validations/resource';

const sortDataMap: Record<ResourceSortType, string> = {
  recent: 'created_at',
  oldest: 'created_at',
  recentRecorded: 'recorded_at',
  oldestRecorded: 'recorded_at',
  filename: 'upload_filename',
  filenameDesc: 'upload_filename',
};

const sortOrderIsDescMap: Record<ResourceSortType, boolean> = {
  recent: true,
  oldest: false,
  recentRecorded: true,
  oldestRecorded: false,
  filename: false,
  filenameDesc: true,
};

export class ResourcesService
  extends ApiClient
  implements ResourcesApiInterface
{
  private sortBalls(
    ballInfoList: {
      ball: Ball;
      positions: BallPosition[];
    }[],
  ) {
    const pitchedBallInfoList = _.chain(ballInfoList)
      .filter((info) => {
        return info.ball.isPitched;
      })
      .sortBy((info) => {
        const firstPos = _.first(info.positions);
        return firstPos?.time ?? Number.MAX_VALUE;
      })
      .value();
    const hitBallInfoList = _.chain(ballInfoList)
      .filter((info) => {
        return info.ball.isHit;
      })
      .sortBy((info) => {
        const firstPos = _.first(info.positions);
        return firstPos?.time ?? Number.MAX_VALUE;
      })
      .value();
    return [...pitchedBallInfoList, ...hitBallInfoList];
  }

  async getResources(
    teamId: string,
    sessionId: string,
    conditions: {
      keyword?: string | null;
      sort?: ResourceSortType;
      dateFilter?: ResourceDateFilterType;
      offset?: number;
      pageSize?: number;
      teamId?: string | null;
      userId?: string | null;
    },
  ): Promise<
    MandatoryOrHavingError<'resources', Resource[]> & { total: number }
  > {
    const _conditions: Required<typeof conditions> = _.defaultsDeep(
      _.cloneDeep(conditions),
      {
        keyword: null,
        sort: 'recent',
        dateFilter: null,
        offset: 0,
        pageSize: 20,
      },
    );

    const { errors, result } = await this.wrapForApiError<{
      resources: Resource[];
      total: number;
    }>(async () => {
      return await this.client.post(
        `teams/${teamId}/sessions/${sessionId}/resources/search`,
        {
          ...conditions,
          dateFrom:
            _conditions.dateFilter == 'all'
              ? null
              : moment(new Date())
                  .subtract(1, _conditions.dateFilter)
                  .add(1, 'day')
                  .startOf('day')
                  .toDate(),
          dateTo: null,
          orderBy: sortDataMap[_conditions.sort],
          isOrderDesc: sortOrderIsDescMap[_conditions.sort],
          page: _conditions.offset / _conditions.pageSize,
        },
      );
    });

    const resources = result?.resources ?? [];
    for (const resource of resources) {
      resource.ballInfoList = this.sortBalls(resource.ballInfoList);
    }

    return {
      ...this.adjustApiResultForMandatoryObject(
        'resources',
        Resource.newInstances(Resource, resources),
        errors,
      ),
      total: result?.total ?? 0,
    };
  }

  async downloadResourcesAsCsv(
    teamId: string,
    sessionId: string,
    conditions: {
      keyword?: string | null;
      sort?: ResourceSortType;
      dateFilter?: ResourceDateFilterType;
      teamId?: string | null;
      userId?: string | null;
      unit: 'm' | 'inch';
    },
  ) {
    const now = new Date();
    const _conditions: Required<typeof conditions> = _.defaultsDeep(
      _.cloneDeep(conditions),
      {
        keyword: null,
        sort: 'recent',
        dateFilter: null,
        offset: 0,
        pageSize: 20,
      },
    );

    const { errors, result } = await this.wrapForApiError<any>(async () => {
      return await this.client.post(
        `teams/${teamId}/sessions/${sessionId}/resources/search/csv`,
        {
          ...conditions,
          dateFrom:
            _conditions.dateFilter == 'all'
              ? null
              : moment(now)
                  .subtract(1, _conditions.dateFilter)
                  .add(1, 'day')
                  .startOf('day')
                  .toDate(),
          dateTo: null,
          orderBy: sortDataMap[_conditions.sort],
          isOrderDesc: sortOrderIsDescMap[_conditions.sort],
        },
        {
          responseType: 'blob',
        },
      );
    });

    const suffixDate = moment(now).format('YYYYMMDD_HHmmss');
    UIUtil.downloadFile(new Blob([result]), `resources_${suffixDate}.csv`);
  }

  async getResourcesForMultiTeams(
    teamIds: string[] | null,
    conditions: {
      keyword?: string | null;
      sort?: ResourceSortType;
      dateFilter?: ResourceDateFilterType;
      playerId?: string | null;
      offset?: number;
      pageSize?: number;
    },
  ): Promise<
    MandatoryOrHavingError<'resources', Resource[]> & { total: number }
  > {
    const _conditions: Required<typeof conditions> = _.defaultsDeep(
      _.cloneDeep(conditions),
      {
        keyword: null,
        sort: 'recent',
        dateFilter: null,
        offset: 0,
        pageSize: 20,
      },
    );

    const { errors, result } = await this.wrapForApiError<{
      resources: Resource[];
      total: number;
    }>(async () => {
      return await this.client.post(`teams/resources/search`, {
        ...conditions,
        dateFrom:
          _conditions.dateFilter == 'all'
            ? null
            : moment(new Date())
                .subtract(1, _conditions.dateFilter)
                .add(1, 'day')
                .startOf('day')
                .toDate(),
        dateTo: null,
        orderBy: sortDataMap[_conditions.sort],
        isOrderDesc: sortOrderIsDescMap[_conditions.sort],
        page: _conditions.offset / _conditions.pageSize,
        ...(teamIds ? { teamIds } : undefined),
      });
    });

    const resources = result?.resources ?? [];
    for (const resource of resources) {
      resource.ballInfoList = this.sortBalls(resource.ballInfoList);
    }

    return {
      ...this.adjustApiResultForMandatoryObject(
        'resources',
        Resource.newInstances(Resource, resources),
        errors,
      ),
      total: result?.total ?? 0,
    };
  }

  async getResource(
    teamId: string,
    sessionId: string,
    resourceId: string,
  ): Promise<MandatoryOrHavingError<'resource', Resource>> {
    const { errors, result } = await this.wrapForApiError<{
      resource: Resource;
    }>(async () => {
      return await this.client.get(
        `teams/${teamId}/sessions/${sessionId}/resources/${resourceId}`,
      );
    });

    if (errors || !result?.resource) {
      return {
        resource: null,
        error: errors,
      };
    }

    const resource = result.resource;
    resource.ballInfoList = this.sortBalls(resource.ballInfoList);

    return this.adjustApiResultForMandatoryObject(
      'resource',
      Resource.newInstance(Resource, resource),
      errors,
    );
  }

  async deleteResource(
    teamId: string,
    sessionId: string,
    resourceId: string,
  ): Promise<{
    error: Error | null;
  }> {
    const { errors, result } = await this.wrapForApiError<{
      resource: Resource;
    }>(async () => {
      return await this.client.delete(
        `teams/${teamId}/sessions/${sessionId}/resources/${resourceId}`,
      );
    });
    return {
      error: errors,
    };
  }

  async analyzeVideo(
    teamId: string,
    sessionId: string,
    param: {
      file: File;
      profileId: string;
      recordedAt: Date | null;
      longsideAngleOfView: number | null;
      focalLength: number | null;
      analyzeType: AnalyzeType;
      unit: SupportedUnit | null;
      language: SupportedLanguage | null;
    },
  ): Promise<MandatoryOrHavingError<'partialResource', Partial<Resource>>> {
    try {
      videoAnalyzeDtoValidator.parse(param);
    } catch (e) {
      return {
        partialResource: null,
        error: new ServiceError(e as ZodError),
      };
    }

    const formData = new FormData();
    formData.append('file', param.file);
    formData.append('sessionId', sessionId);
    formData.append('profileId', param.profileId);
    if (param.recordedAt) {
      formData.append(
        'recordedAt',
        moment(param.recordedAt).format(AppConstants.API_DATETIME_FORMAT),
      );
    }
    if (!_.isNil(param.longsideAngleOfView)) {
      formData.append(
        'longsideAngleOfView',
        param.longsideAngleOfView.toString(),
      );
    }
    if (!_.isNil(param.focalLength)) {
      formData.append('focalLength', param.focalLength.toString());
    }
    if (_.isString(param.analyzeType)) {
      formData.append(
        'analyzeType',
        analyzeTypeValuesMap[param.analyzeType].toString(),
      );
    }
    if (!_.isNil(param.unit)) {
      formData.append('unit', param.unit);
    }
    if (!_.isNil(param.language)) {
      formData.append('lang', param.language);
    }

    const { result, errors } = await this.wrapForApiError<{
      resource: {
        id: string;
