import _ from 'lodash';
import moment from 'moment';

import { Session } from '@/models/session';
import { MandatoryOrHavingError } from '@/models/types';
import { ApiClient } from '@/services/clients/web-api-client';
import { ServiceError } from '@/services/errors/service-error';
import {
  CreateSessionParam,
  SessionDateFilterType,
  SessionsApiInterface,
  SessionSortType,
} from '@/services/interfaces/sessions-api.interface';
import { UIUtil } from '@/utils/ui.util';

const sortDataMap: Record<SessionSortType, string> = {
  recent: 'created_at',
  oldest: 'created_at',
  location: 'location',
  locationDesc: 'location',
  title: 'title',
  titleDesc: 'title',
};

const sortIsDescMap: Record<SessionSortType, boolean> = {
  recent: true,
  oldest: false,
  location: false,
  locationDesc: true,
  title: false,
  titleDesc: true,
};

export class SessionsService extends ApiClient implements SessionsApiInterface {
  static readonly code = 'SSS';

  get code() {
    return SessionsService.code;
  }

  async getSessions(
    teamId: string,
    conditions: {
      keyword?: string | null;
      sort?: SessionSortType;
      dateFilter?: SessionDateFilterType;
      offset?: number;
      pageSize?: number;
      userId?: string | null;
      playerId?: string | null;
      location?: string | null;
    },
  ): Promise<
    MandatoryOrHavingError<'sessions', Session[]> & { total: number }
  > {
    const _conditions: Required<typeof conditions> = _.defaultsDeep(
      _.cloneDeep(conditions),
      {
        keyword: null,
        sort: 'recent',
        dateFilter: null,
        offset: 0,
        pageSize: 20,
        userId: null,
      },
    );
    const now = new Date();
    const { errors, result } = await this.wrapForApiError<{
      sessions: Session[];
      total: number;
    }>(async () => {
      return await this.client.post(`teams/${teamId}/sessions/search`, {
        keyword: _conditions.keyword,
        playerId: _conditions.playerId,
        userId: _conditions.userId,
        dateFrom:
          _conditions.dateFilter == 'all'
            ? null
            : moment(new Date())
                .subtract(1, _conditions.dateFilter)
                .add(1, 'day')
                .startOf('day')
                .toDate(),
        dateTo: null,
        page: _conditions.offset / _conditions.pageSize,
        pageSize: _conditions.pageSize,
        orderBy: sortDataMap[_conditions.sort] ?? 'id',
        isOrderDesc: sortIsDescMap[_conditions.sort] ?? false,
        location: _conditions.location,
      });
    });

    return {
      ...this.adjustApiResultForMandatoryObject(
        'sessions',
        Session.newInstances(Session, result?.sessions),
        errors,
      ),
      total: result?.total ?? 0,
    };
  }

  async downloadSessionsAsCsv(
    teamId: string,
    conditions: {
      keyword?: string | null;
      sort?: SessionSortType;
      dateFilter?: SessionDateFilterType;
      userId?: string | null;
      playerId?: string | null;
      location?: string | null;
      unit: 'm' | 'inch';
    },
  ) {
    const _conditions: Required<typeof conditions> = _.defaultsDeep(
      _.cloneDeep(conditions),
      {
        keyword: null,
        sort: 'recent',
        dateFilter: null,
        offset: 0,
        pageSize: 20,
        userId: null,
      },
    );
    const now = new Date();
    const { errors, result } = await this.wrapForApiError<any>(async () => {
      return await this.client.post(
        `teams/${teamId}/sessions/search/csv`,
        {
          keyword: _conditions.keyword,
          playerId: _conditions.playerId,
          userId: _conditions.userId,
          dateFrom:
            _conditions.dateFilter == 'all'
              ? null
              : moment(now)
                  .subtract(1, _conditions.dateFilter)
                  .add(1, 'day')
                  .startOf('day')
                  .toDate(),
          dateTo: null,
          orderBy: sortDataMap[_conditions.sort] ?? 'id',
          isOrderDesc: sortIsDescMap[_conditions.sort] ?? false,
          location: _conditions.location,
          unit: conditions.unit,
        },
        {
          responseType: 'blob',
        },
      );
    });

    const suffixDate = moment(now).format('YYYYMMDD_HHmmss');
    UIUtil.downloadFile(new Blob([result]), `sessions_${suffixDate}.csv`);
  }

  async getSessionsForSuperAdmin(conditions: {
    keyword?: string | null;
    sort?: SessionSortType;
    dateFilter?: SessionDateFilterType;
    offset?: number;
    pageSize?: number;
    userId?: string | null;
    playerId?: string | null;
    location?: string | null;
    unit: 'm' | 'inch';
  }): Promise<
    MandatoryOrHavingError<'sessions', Session[]> & { total: number }
  > {
    const _conditions: Required<typeof conditions> = _.defaultsDeep(
      _.cloneDeep(conditions),
      {
        keyword: null,
        sort: 'recent',
        dateFilter: null,
        offset: 0,
        pageSize: 20,
        userId: null,
      },
    );
    const now = new Date();
    const { errors, result } = await this.wrapForApiError<{
      sessions: Session[];
      total: number;
    }>(async () => {
      return await this.client.post(`teams/sessions/search`, {
        keyword: _conditions.keyword,
        playerId: _conditions.playerId,
        userId: _conditions.userId,
        dateFrom:
          _conditions.dateFilter == 'all'
            ? null
            : moment(new Date())
                .subtract(1, _conditions.dateFilter)
                .add(1, 'day')
                .startOf('day')
                .toDate(),
        dateTo: null,
        page: _conditions.offset / _conditions.pageSize,
        pageSize: _conditions.pageSize,
        orderBy: sortDataMap[_conditions.sort] ?? 'id',
        isOrderDesc: sortIsDescMap[_conditions.sort] ?? false,
        location: _conditions.location,
        unit: conditions.unit,
      });
    });

    return {
      ...this.adjustApiResultForMandatoryObject(
        'sessions',
        Session.newInstances(Session, result?.sessions),
        errors,
      ),
      total: result?.total ?? 0,
    };
  }

  async getLocations(
    teamId: string,
    userId: string | null,
  ): Promise<MandatoryOrHavingError<'locations', string[]>> {
    const { errors, result } = await this.wrapForApiError(async () => {
      return await this.client.get(`teams/${teamId}/sessions/locations`, {
        params: userId
          ? {
              userId,
            }
          : {},
      });
    });

    return this.adjustApiResultForMandatoryObject(
      'locations',
      result?.locations ?? null,
      errors,
    );
  }

  async getLocationsForSuperAdmin(): Promise<
    MandatoryOrHavingError<'locations', string[]>
  > {
    const { errors, result } = await this.wrapForApiError(async () => {
      return await this.client.get(`teams/sessions/locations`);
    });

    return this.adjustApiResultForMandatoryObject(
      'locations',
      result?.locations ?? null,
      errors,
    );
  }

  async getSession(
    teamId: string,
    sessionId: string,
  ): Promise<MandatoryOrHavingError<'session', Session>> {
    const { errors, result } = await this.wrapForApiError(async () => {
      return await this.client.get(`teams/${teamId}/sessions/${sessionId}`);
    });

    return this.adjustApiResultForMandatoryObject(
      'session',
      Session.newInstance(Session, result?.session),
      errors,
    );
  }

  async createSession(
    teamId: string,
    param: CreateSessionParam,
  ): Promise<MandatoryOrHavingError<'session', Session>> {
    const { errors, result } = await this.wrapForApiError(async () => {
      return await this.client.post(`teams/${teamId}/sessions`, {
        title: param.title,
        location: param.location,
        playerId: param.playerId,
        note: param.note,
      });
    });

    return this.adjustApiResultForMandatoryObject(
      'session',
      Session.newInstance(Session, result?.session),
      errors,
    );
  }

  async updateSession(
    teamId: string,
    sessionId: string,
    data: {
      title?: string;
      location?: string | null;
      note?: string;
      playerId?: string;
    },
  ): Promise<{
    session: Session | null;
    error: ServiceError | null;
  }> {
    const { errors, result } = await this.wrapForApiError(async () => {
      return await this.client.put(`teams/${teamId}/sessions/${sessionId}`, {
        title: data.title,
        location: data.location,
        note: data.note,
        playerId: data.playerId,
      });
    });

    return this.adjustApiResultForMandatoryObject(
      'session',
      Session.newInstance(Session, result?.session),
      errors,
    );
  }

  async deleteSession(
    teamId: string,
    sessionId: string,
  ): Promise<{ error: Error | null }> {
    const { errors, result } = await this.wrapForApiError(async () => {
      return await this.client.delete(`teams/${teamId}/sessions/${sessionId}`);
    });

    return {
      error: null,
    };
  }
}

