import _ from 'lodash';

import {
  defaultDateOptions,
  DefaultDateOptionValue,
} from '@/constants/app.constants';
import { SupportedLanguage, SupportedUnit } from '@/constants/app.constants';
import { Resource } from '@/models/resource';
import { MandatoryOrHavingError } from '@/models/types';
import { ServiceError } from '@/services/errors/service-error';

export type ResourceDateFilterType = DefaultDateOptionValue;
export const resourceDefaultDateOptions = defaultDateOptions;
export const resourceSortTypes = [
  'recent',
  'oldest',
  'recentRecorded',
  'oldestRecorded',
  'filename',
  'filenameDesc',
] as const;
export type ResourceSortType = (typeof resourceSortTypes)[number];

export const analyzeTypeValuesMap = Object.freeze({
  pitching: 1,
  hitting: 2,
  both: 3,
  pitching_all: 4,
  hitting_all: 5,
});
export type AnalyzeType = keyof typeof analyzeTypeValuesMap;

export interface ResourcesApiInterface {
  getResources(
    teamId: string,
    sessionId: string,
    conditions: {
      keyword?: string | null;
      sort?: ResourceSortType;
      dateFilter?: ResourceDateFilterType;
      offset?: number;
      pageSize?: number;
      teamId?: string | null;
      userId?: string | null;
    },
  ): Promise<
    MandatoryOrHavingError<'resources', Resource[]> & { total: number }
  >;

  downloadResourcesAsCsv(
    teamId: string,
    sessionId: string,
    conditions: {
      keyword?: string | null;
      sort?: ResourceSortType;
      dateFilter?: ResourceDateFilterType;
      teamId?: string | null;
      userId?: string | null;
      unit: 'm' | 'inch';
    },
  ): void;

  getResourcesForMultiTeams(
    teamIds: string[] | null,
    conditions: {
      keyword?: string | null;
      sort?: ResourceSortType;
      dateFilter?: ResourceDateFilterType;
      playerId?: string | null;
      offset?: number;
      pageSize?: number;
    },
  ): Promise<
    MandatoryOrHavingError<'resources', Resource[]> & { total: number }
  >;

  getResource(
    teamId: string,
    sessionId: string,
    resourceId: string,
  ): Promise<MandatoryOrHavingError<'resource', Resource>>;

  deleteResource(
    teamId: string,
    sessionId: string,
    resourceId: string,
  ): Promise<{
    error: Error | null;
  }>;

  analyzeVideo(
    teamId: string,
    sessionId: string,
    param: {
      file: File;
      profileId: string;
      recordedAt: Date | null;
      longsideAngleOfView: number | null;
      focalLength: number | null;
      analyzeType: AnalyzeType;
      unit: SupportedUnit | null;
      language: SupportedLanguage | null;
    },
  ): Promise<MandatoryOrHavingError<'partialResource', Partial<Resource>>>;

  reAnalyze(
    teamId: string,
    sessionId: string,
    resourceId: string,
  ): Promise<{ error: ServiceError | null }>;
}

