   266→      dateFilter: conditions.filter,
   267→      offset: conditions.currentPage * conditions.rowsPerPage,
   268→      pageSize: conditions.rowsPerPage,
   269→      location: conditions.location,
   270→      userId: hasCrossAccessInTeam ? null : currentUser.id,
   271→    };
   272→    const result = await services.default.session.getSessions(
