import { Notification } from '@/models/notification';
import { Plan } from '@/models/plan';
import { Team } from '@/models/team';
import { MandatoryOrHavingError } from '@/models/types';
import { ServiceError } from '@/services/errors/service-error';

export type CreateTeamParam = {
  name: string;
  planId: string | null;
  teamPlanStartDate: Date;
  teamPlanEndDate: Date;
  userName: string | null;
  email: string;
  role: string | null;
  password: string | null;
  passwordConfirmation: string | null;
  createOwnerAccount: boolean;
  language: string | null;
  ownerBirthday: Date | null;
};

export type CreateTeamPlanParam = {
  planId: string;
  startDate: Date;
  endDate: Date;
};

export type UpdateTeamPlanParam = {
  planId: string;
  startDate: Date;
  endDate: Date;
  isActive?: boolean;
};

export const teamSortTypes = [
  'recent',
  'oldest',
  'teamPlanStartDate',
  'teamPlanStartDateDesc',
  'teamPlanEndDate',
  'teamPlanEndDateDesc',
] as const;
export type TeamSortType = (typeof teamSortTypes)[number];

export const planFilterTypes = ['all', 'free', 'paid'] as const;
export type PlanFilterType = (typeof planFilterTypes)[number];

export const teamTypeFilterTypes = ['all', 'single', 'multiple'] as const;
export type TeamTypeFilterType = (typeof teamTypeFilterTypes)[number];

export const teamPlanExpiryFilterTypes = [
  'all',
  'before1Week',
  'before2Weeks',
  'after1Week',
  'after2Weeks',
] as const;
export type TeamPlanExpiryFilterType =
  (typeof teamPlanExpiryFilterTypes)[number];

export interface SuperAdminApiInterface {
  getPlans(conditions: {
    keyword?: string | null;
    offset?: number;
    pageSize?: number;
  }): Promise<MandatoryOrHavingError<'plans', Plan[]> & { total: number }>;
  getTeams(conditions: {
    keyword?: string | null;
    sort?: TeamSortType;
    expiryFilter?: TeamPlanExpiryFilterType;
    planFilter?: PlanFilterType;
    teamTypes?: ('single' | 'multiple')[];
    teamOwner?: string | null;
    extendToNextTeamPlan?: boolean;
    offset?: number;
    pageSize?: number;
  }): Promise<MandatoryOrHavingError<'teams', Team[]> & { total: number }>;
  createTeamPlan(
    teamId: string,
    data: CreateTeamPlanParam,
  ): Promise<MandatoryOrHavingError<'team', Team>>;
  updateTeamPlan(
    teamId: string,
    teamPlanId: string,
    data: UpdateTeamPlanParam,
  ): Promise<MandatoryOrHavingError<'team', Team>>;
  deleteNextTeamPlan(
    teamId: string,
    teamPlanId: string,
  ): Promise<MandatoryOrHavingError<'team', Team>>;
  createNewTeam(
    param: CreateTeamParam,
  ): Promise<MandatoryOrHavingError<'team', Team>>;
  getNotification(
    notificationId: string,
  ): Promise<MandatoryOrHavingError<'notification', Notification>>;
  getNotifications(conditions: {
    keyword?: string | null;
    targetTeamTypes?: string[];
    offset?: number;
    pageSize?: number;
  }): Promise<
    MandatoryOrHavingError<'notifications', Notification[]> & { total: number }
  >;
  createNotification(data: {
    titleEn?: string;
    titleJa?: string;
    contentsEn?: string;
    contentsJa?: string;
    targetType?: string;
    targetTeamTypes?: string[];
    publishAt?: Date | null;
    isImportant?: boolean;
  }): Promise<MandatoryOrHavingError<'notification', Notification>>;
  updateNotification(
    notificationId: string,
    data: {
      titleEn?: string;
      titleJa?: string;
      contentsEn?: string;
      contentsJa?: string;
      targetType?: string;
      targetTeamTypes?: string[];
      publishAt?: Date | null;
      isImportant?: boolean;
    },
  ): Promise<MandatoryOrHavingError<'notification', Notification>>;
  deleteNotification(notificationId: string): Promise<{ error: ServiceError }>;
}

