import {
  Dispatch,
  FC,
  ReactNode,
  SetStateAction,
  useMemo,
  useState,
} from 'react';

import useServicesHook from '@/hooks';
import { ServiceError } from '@/services/errors/service-error';
import { CreateTeamPlanParam } from '@/services/interfaces/super-admin-api.interface';
import { wrapForLoading } from '@/utils/functions/transformer';

import { BaseTeamPlanModal } from './base-team-plan-modal';

export const CreateTeamPlanModal: FC<{
  teamId: string | null;
  defaultDate: Date | null;
  title: ReactNode;
  isOpen: boolean;
  setIsOpen: Dispatch<SetStateAction<boolean>>;
  onFail?: Function;
  onSuccess?: Function;
}> = ({ teamId, defaultDate, title, isOpen, setIsOpen, onFail, onSuccess }) => {
  const { services, dispatch } = useServicesHook();
  const [error, setError] = useState<ServiceError | null>(null);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const defaultParam = useMemo(
    () =>
      defaultDate
        ? {
            startDate: defaultDate,
            endDate: defaultDate,
          }
        : {},
    [defaultDate],
  );

  const createTeamPlan = async (param: CreateTeamPlanParam) => {
    wrapForLoading(setIsSubmitting, async () => {
      const { error, team: _ } =
        await services.default.superAdmin.createTeamPlan(
          teamId!,
          param as CreateTeamPlanParam,
        );

      if (error) {
        onFail?.();
        setError(error);
        return;
      }

      onSuccess?.();
      setIsOpen(false);
    });
  };

  return (
    <BaseTeamPlanModal
      title={title}
      error={error}
      setError={setError}
      isOpen={isOpen}
      setIsOpen={setIsOpen}
      isSubmitting={isSubmitting}
      teamId={teamId}
      teamPlan={defaultParam}
      onOk={createTeamPlan}
    />
  );
};

