import { Dispatch, FC, SetStateAction, useState } from 'react';

import useServicesHook from '@/hooks';
import { TeamPlan } from '@/models/team-plan';
import { ServiceError } from '@/services/errors/service-error';
import {
  CreateTeamPlanParam,
  UpdateTeamPlanParam,
} from '@/services/interfaces/super-admin-api.interface';
import { wrapForLoading } from '@/utils/functions/transformer';
import { translate } from '@/utils/i18n';

import { ConfirmationModal } from '../confirmation-modal';
import { BaseTeamPlanModal, BaseTeamPlanParam } from './base-team-plan-modal';

export const EditOrDeleteNextTeamPlanModal: FC<{
  teamId: string | null;
  teamPlan: TeamPlan | null;
  isOpen: boolean;
  setIsOpen: Dispatch<SetStateAction<boolean>>;
  onFail?: Function;
  onSuccess?: Function;
}> = ({ teamId, teamPlan, isOpen, setIsOpen, onFail, onSuccess }) => {
  const { services, dispatch } = useServicesHook();
  const [error, setError] = useState<ServiceError | null>(null);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [isDeleting, setIsDeleting] = useState<boolean>(false);
  const [isConfirmationModalOpen, setIsConfirmationModalOpen] =
    useState<boolean>(false);

  const createTeamPlan = async (param: CreateTeamPlanParam) => {
    wrapForLoading(setIsSubmitting, async () => {
      const { error, team: _ } =
        await services.default.superAdmin.createTeamPlan(
          teamId!,
          param as CreateTeamPlanParam,
        );

      if (error) {
        onFail?.();
        setError(error);
        return;
      }

      onSuccess?.();
      setIsOpen(false);
    });
  };

  const updateNextTeamPlan = async (param: BaseTeamPlanParam) => {
    wrapForLoading(setIsSubmitting, async () => {
      const { error, team: _ } =
        await services.default.superAdmin.updateTeamPlan(
          teamId!,
          teamPlan!.id,
          param as UpdateTeamPlanParam,
        );

      if (error) {
        onFail?.();
        setError(error);
        return;
      }

      onSuccess?.();
      setIsOpen(false);
    });
  };

  const deleteNextTeamPlan = async () => {
    wrapForLoading(setIsDeleting, async () => {
      const { error, team: _ } =
        await services.default.superAdmin.deleteNextTeamPlan(
          teamId!,
          teamPlan!.id,
        );

      if (error) {
        onFail?.();
        setError(error);
        return;
      }

      onSuccess?.();
      setIsOpen(false);
    });
  };

  return (
    <>
      <ConfirmationModal
        title={translate('delete_next_team_plan')}
        isOpen={isConfirmationModalOpen}
        setIsOpen={setIsConfirmationModalOpen}
        isDeleteMode={true}
        cbOk={deleteNextTeamPlan}
      />
      <BaseTeamPlanModal
        title={translate('edit_or_delete_next_team_plan')}
        error={error}
        setError={setError}
        isOpen={isOpen}
        setIsOpen={setIsOpen}
        isSubmitting={isSubmitting}
        isDeleting={isDeleting}
        teamId={teamId}
        teamPlan={teamPlan}
        onOk={teamPlan ? updateNextTeamPlan : createTeamPlan}
        onDelete={() => setIsConfirmationModalOpen(true)}
      />
    </>
  );
};

