import {
  Box,
  Button,
  FormControl,
  FormControlLabel,
  InputLabel,
  MenuItem,
  Select,
  Stack,
  Switch,
  TextField,
  Typography,
} from '@mui/material';
import { DateTimePicker } from '@mui/x-date-pickers';
import _ from 'lodash';
import moment from 'moment';
import {
  ChangeEvent,
  Dispatch,
  FC,
  ReactNode,
  SetStateAction,
  useEffect,
  useId,
  useState,
} from 'react';

import CriticalError from '@/components/common/critical-error';
import ValidationError from '@/components/common/validation-error';
import { maxDateTime, minDateTime } from '@/constants/app.constants';
import useServicesHook from '@/hooks';
import { Plan } from '@/models/plan';
import { TeamPlan } from '@/models/team-plan';
import { ServiceError } from '@/services/errors/service-error';
import { translate } from '@/utils/i18n';

import { CommonModal } from '../common-modal';

export type BaseTeamPlanParam = {
  planId: string;
  startDate: Date;
  endDate: Date;
  isActive: boolean;
};

const getDefaultParam = (): Partial<BaseTeamPlanParam> => {
  const today = moment().startOf('day').toDate();
  return {
    planId: undefined,
    startDate: today,
    endDate: today,
    isActive: true,
  };
};

export const BaseTeamPlanModal: FC<{
  title: ReactNode;
  teamId: string | null;
  teamPlan: Partial<TeamPlan> | null;
  isOpen: boolean;
  setIsOpen: Dispatch<SetStateAction<boolean>>;
  isSubmitting: boolean;
  isDeleting?: boolean;
  showIsActiveSelector?: boolean;
  error: ServiceError | null;
  setError: Dispatch<SetStateAction<ServiceError | null>>;
  onOk?: (param: BaseTeamPlanParam) => Promise<void>;
  onDelete?: Function;
  onCancel?: Function;
}> = ({
  title,
  teamId,
  teamPlan,
  isOpen,
  setIsOpen,
  isSubmitting,
  isDeleting,
  showIsActiveSelector,
  error,
  setError,
  onOk,
  onDelete,
  onCancel,
}) => {
  const { services, dispatch } = useServicesHook();

  const [param, setParam] =
    useState<Partial<BaseTeamPlanParam>>(getDefaultParam());
  const [plans, setPlans] = useState<Plan[]>([]);

  const idForPlanId = useId();

  const isCurrentTeamPlan =
    teamPlan?.startDate &&
    teamPlan?.endDate &&
    +new Date(teamPlan.startDate) <= +new Date() &&
    +new Date(teamPlan.endDate) > +new Date();

  const getPlans = async () => {
    const { plans, total, error } = await services.default.superAdmin.getPlans(
      {},
    );

    if (error) {
      setError(error);
      return;
    }

    setPlans(plans);
  };

  useEffect(() => {
    if (isOpen) {
      // reset
      getPlans();
      setParam(_.defaults({}, teamPlan, getDefaultParam()));
      setError(null);
    }
  }, [isOpen]);

  if (plans.length == 0 || teamId === null) {
    return <></>;
  }

  return (
    <CommonModal isOpen={isOpen} setIsOpen={setIsOpen} onClose={onCancel}>
      <Typography variant="h4">{title}</Typography>
      <Stack alignItems="stretch" direction="column" spacing={2} sx={{ mt: 2 }}>
        {isCurrentTeamPlan && (
          <Typography color="warning">
            {translate('note_edit_current_team_plan')}
          </Typography>
        )}
        <FormControl>
          <InputLabel id={idForPlanId}>{translate('plan')}</InputLabel>
          <Select
            id="plan-label"
            size="medium"
            variant="outlined"
            value={param.planId ?? ''}
            sx={{ minWidth: '10rem' }}
            label={translate('plan')}
            onChange={(e) => {
              if (!e.target.value) {
                return;
              }
              setParam({
                ...param,
                planId: e.target.value,
              });
            }}
          >
            {_.map(plans, (x) => {
              return (
                <MenuItem key={x.id} value={x.id}>
                  {x.isPaid ? '💲' : '🆓️'} {x.name}
                </MenuItem>
              );
            })}
          </Select>
          <ValidationError error={error} pos={['planId']} />
        </FormControl>
        {showIsActiveSelector && (
          <>
            <FormControl>
              <FormControlLabel
                control={
                  <Switch
                    checked={param.isActive}
                    onChange={(e) => {
                      setParam({ ...param, isActive: e.target.checked });
                    }}
                  />
                }
                label={translate('activate_team_plan')}
              />
              <ValidationError error={error} pos={['isActive']} />
            </FormControl>
          </>
        )}
        <FormControl>
          <DateTimePicker
            label={translate('start_datetime_local')}
            value={moment(param.startDate!)}
            onChange={(value) => {
              setParam({
                ...param,
                startDate: value?.toDate(),
              });
            }}
            minDateTime={minDateTime}
            maxDateTime={maxDateTime}
          />
          <ValidationError error={error} pos={['startDate']} />
        </FormControl>
        <FormControl>
          <DateTimePicker
            label={translate('end_datetime_local')}
            value={moment(param.endDate)}
            onChange={(value) => {
              setParam({
                ...param,
                endDate: value?.toDate(),
              });
            }}
            minDateTime={minDateTime}
            maxDateTime={maxDateTime}
          />
          <ValidationError error={error} pos={['endDate']} />
        </FormControl>

        <CriticalError error={error} />

        <Box sx={{ pt: 2 }}>
          <Button
            color="primary"
            fullWidth
            loading={isSubmitting}
            disabled={isDeleting}
            variant="contained"
            onClick={() => {
              onOk?.(param as BaseTeamPlanParam);
            }}
          >
            {translate('button_save_changes')}
          </Button>

          <Button
            fullWidth
            disabled={isSubmitting || isDeleting}
            color="neutral"
            variant={onDelete ? 'outlined' : undefined}
            sx={{ mt: 2 }}
            onClick={() => {
              setIsOpen(false);
            }}
          >
            {translate('button_discard')}
          </Button>

          {onDelete && (
            <Button
              fullWidth
              loading={isDeleting}
              disabled={isSubmitting}
              color="error"
              variant="contained"
              sx={{ mt: 2 }}
              onClick={() => onDelete()}
            >
              {translate('button_delete')}
            </Button>
          )}
        </Box>
      </Stack>
    </CommonModal>
  );
};
